            toStringOutput.Add($"ProductTransaction = {(this.ProductTransaction == null ? "null" : this.ProductTransaction.ToString())}");

            additionalProperties?
                .Select(kvp => $"[{kvp.Key}] = {kvp.Value.ToString(Formatting.None)}")
                .ToList()
                .ForEach(toStringOutput.Add);
        }
    }
}